const PROCESSING_FEE = 5;
const SINGLE_SWORD_PREMIUM = 115;

type Step = { op: "quote"; items: unknown[] };
type Scenario = { customer: unknown; steps: Step[] };
type QuoteResult = { premium: number };

const quote = (items: unknown[]): QuoteResult => {
  if (items.length === 0) return { premium: PROCESSING_FEE };
  return { premium: SINGLE_SWORD_PREMIUM };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map((step) => quote(step.items));
  return { results };
};

